    // .............
    // #2: ATimeofWarIntro

    void passage2_Init()
    {
        this.Passages[@"ATimeofWarIntro"] = new StoryPassage(@"ATimeofWarIntro", new string[] { "INTRO", }, passage2_Main);
    }

    IStoryThread passage2_Main()
    {
        //yield return lineBreak(); //hr tag
        using (styleScope("bold", true))
        {
            yield return text("GENERATION I: Taking Sides");
        }
        yield return lineBreak();
        yield return lineBreak(); //hr tag
        yield return text(@"My father was a genius! I state this now, not with the naïveté of my initial discovery of his journal, but as a time-tested statement of truth. It is why I pen these words today for posterity and to affirm with deep conviction what some may erroneously refer to as mad science.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"When I first arrived at my father's manor, I carried the same skepticism any normal individual would. Weary as I was from the excursion across the Hungarian plains, the cold, gray walls of the villa with its oppressive iron gates chilled me to my marrow. When the disfigured caretaker — the only person privileged with the knowledge — revealed to me a false door and spiraling staircase that descended to a secret laboratory, the grim discovery did nothing to soothe my nerves. In fact, the sight of jars filled with preserved flesh and the astringent stench of chemicals aggravated my frail state, leaving me to take my suppers in the bedroom for several weeks. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"But, it was this same dark discovery that eventually roused me from my illness. For as I pored over the journal bequeathed to me and surveyed page after page of formulaic experimentation, my apprehensions melted. I felt trepidacious, yet unreservedly enthusiastic at the ethical implications of this great task!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Yet even after the disquiet within my soul was relieved, the nearby village rattled my window panes with cacophonous revelry. At first, I kept my visits to the borough brief and infrequent. It seemed that whenever I turned my head I would lock eyes with a cautious observer, and I felt the entire town's steel gaze like daggers tickling the back of my skull. I could only speculate that my siblings endured the same sordid treatment.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It was my spouse, using my extended rest to become better acquainted with the village, who explained how spirited political discourse was the source of this commotion. Then I could discern the rally cry of their evening demonstrations as they spoke of disobedience, the end of monarchy, and civil war. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I began to realize the potential boon that war could provide for my research. If the people shared a mere fraction of the passion that now stoked the fires of my heart, how easily they would embrace my scientific assistance! While my father's ambitions were strong, his solitary existence had doomed his ideas to obscurity. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I would not repeat this error. I would brave the jeers of the populace to guide them in the art of warfare. My efforts would determine the course of this conflict. And when the time comes, it will be my science that will emerge from the flames of war as the true victor!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "IntroConflict", null);
        yield return lineBreak();
        Vars.rumblings = 0;
        Vars.war = macros1.either(1, 2);
        Vars.warwinner = macros1.either("Separatists", "Unified Monarchists");
        if (Vars.warwinner == "Separatists")
        {
            Vars.crest = "Sickle";
            Vars.warloser = "Unified Monarchists";
            Vars.figure = "Shield";
        }
        else //if (Vars.warwinner == "Unified Monarchists")
        {
            Vars.crest = "Shield";
            Vars.warloser = "Separatists";
            Vars.figure = "Sickle";
        }

        if (Vars.warwinner == "Separatists")
        {
            Vars.quarter = macros1.either("yes", "no");
        }
        Vars.crazy = 0;
        Vars.barracksact = macros1.either("mean", "nice");
        Vars.sep = 0;
        Vars.mon = 0;
        Vars.gunsbonus = 0;
        yield return lineBreak();
        yield break;
    }


