                yield return lineBreak(); //br tag
                yield return text("Turn to the ");
                using (styleScope("bold", true))
                {
                    yield return text("A Time of War");
                }
                yield return text(" section of the Village Chronicle. Then, turn to page ");
                using (styleScope("bold", true))
                {
                    yield return text("1");
