        }
        yield return lineBreak();
        using (styleScope("hubDetails", true))
        {
            yield return text("When you visit the Town Hall, you may trade a Knowledge cube you have in your Qua" +
            "rters for any other Knowledge cube from the supply. You may perform this trade a" +
            "s many times as you like. ");
