    // #6: RumorD

    void passage6_Init()
    {
        this.Passages[@"RumorD"] = new StoryPassage(@"RumorD", new string[] { }, passage6_Main);
    }

    IStoryThread passage6_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Visit the Town Hall");
        }
        yield return lineBreak();
        yield return text(@"I decided to attend one of several scheduled city council meetings at the Town Hall. ");
        yield return text(macros1.either("For such a small, rural village, the atmosphere was always busy with at least one" +
            " boisterous argument erupting after the charged words of a townsperson. This liv" +
            "ely arrangement intrigued me, and I decided to investigate further.", @"While the sights - and smells - of the local civic establishment were certainly an interesting diversion, I could not allow myself to be distracted. I was here to gain insight on the political factions, as I was well-aware that this knowledge could be swung to my advantage.", @"I was never quite fond of my visits to this place. However, it was ever my duty to make an appearance and my spouse insisted that I would do well to 'mingle' amongst the folk here. So, I made do within the strained situation and struck up a conversation with the first individual that intrigued me.", @"These spirited events - possible more entertaining to observe than to engage with - took place as the sun set and then sprawled late into the evening. I found myself much more accepted in this environment as the night wore on and inevitably the spirits of all in attendance were roused by the spirits from a local distillery. On this peculiar evening, a few persons caught my eye."));

        yield return lineBreak();
        Vars.rumblings = int.Parse(Vars.rumblings) + 1;
        yield return lineBreak();
        yield return text("<b>I chose to converse with:</b>");
        yield return lineBreak();
        yield return lineBreak();
        Vars.rumor = macros1.a(1, 2, 3, 4, 5, 6);
        if (Vars.rumor1 == "visited")
        {
            Vars.rumor = Vars.rumor - macros1.a(1);
        }
        if (Vars.rumor2 == "visited")
        {
            Vars.rumor = Vars.rumor - macros1.a(2);
        }
        if (Vars.rumor6 == "visited")
        {
            Vars.rumor = Vars.rumor - macros1.a(6);
        }
        Vars.rumor = macros1.shuffled((HarloweSpread)Vars.rumor);
        Vars.opt1 = Vars.rumor["1st"];
        Vars.opt2 = Vars.rumor["2nd"];
        if (Vars.opt1 == 1)
        {
            yield return link("A guard dressed in military regalia near the front door.", "RumorD1", null);
        }
        if (Vars.opt1 == 2)
        {
            yield return link("A distinguished gentleman near the stage; his whiskers well-waxed.", "RumorD2", null);
        }
        if (Vars.opt1 == 5)
        {
            yield return link("A somber elderly woman sitting amongst the crowd.", "RumorD3", null);
        }
        if (Vars.opt1 == 4)
        {
            yield return link("A spirited group of concerned citizens.", "RumorD4", null);
        }
        if (Vars.opt1 == 3)
        {
            yield return link("A hunched figure with a broken front-tooth, observing with mirth from the shadows" +
            ".", "RumorD5", null);
        }
        if (Vars.opt1 == 6)
        {
            yield return link("A conservatively dressed woman shuffling papers in her lap.", "RumorD6Guns", null);
        }
        yield return lineBreak(); //br tag
        yield return lineBreak(); //br tag
        if (Vars.opt2 == 1)
        {
            yield return link("A guard dressed in military regalia near the front door.", "RumorD1", null);
        }
        if (Vars.opt2 == 2)
        {
            yield return link("A distinguished gentleman near the stage; his whiskers well-waxed.", "RumorD2", null);
        }
        if (Vars.opt2 == 5)
        {
            yield return link("A somber elderly woman sitting amongst the crowd.", "RumorD3", null);
        }
        if (Vars.opt2 == 4)
        {
            yield return link("A spirited group of concerned citizens.", "RumorD4", null);
        }
        if (Vars.opt2 == 3)
        {
            yield return link("A hunched figure with a broken front-tooth, observing with mirth from the shadows" +
