    IStoryThread passage41_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III: Heavy is the Crown");
        }
        yield return lineBreak();
        yield return lineBreak(); //hr tag
        yield return text("Influence is gained in two ways: through money (that alluring and insidious scrat" +
            "ch) and through bloodshed. Though my years on this foul Earth are few, in this a" +
            "bbreviated time I have learned this one valuable truth.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The voracious objections of the townsfolk had become so commonplace that to see them reduced to sneering murmurs was a marked improvement that made my excursions to the village supremely more tolerable. The Separatist movement had dissipated with time, which put an end to this exasperating (yet lucrative) warring business and the peasantry returned to their normal state of impotent discontent.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"By this time, our family's influence had bent the ear of the throne. With keen use of investment capital, we were afforded an advisory position that could be employed to sway official opinion and deal with regional matters. This presented a delicate balance: As long as our work went unnoticed, we could avoid all consequences and remain influential. Once noticed, however, we could never return to the same peace once afforded. Heavy is the head that wears the crown, as the bard says.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I was excited at the proposition, and instructed my servants to be at their finest for potential visitors; because while I grew lethargic at the thought of entertaining clerical matters of the crown, I fully recognized the power that one could wield with proper control of the state. And whether I had to bury them in gold or watch the rivers run red with blood, I would be afforded that power!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "RoyalBarnCheck", null);
        yield return lineBreak();
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        if (Vars.MonarchReignIntro == 0 || Vars.MonarchReignIntro == "")
        {
            Vars.MonarchReignIntro = 1;
            Vars.tracker = int.Parse(Vars.tracker) - 1;
            if (Vars.players == 5)
            {
                Vars.tracker = int.Parse(Vars.tracker) - 1;
            }
        }
        Vars.decbon = macros1.either(5, 6, 7, 8);
        if (Vars.warloser == "Unified Monarchists")
        {
            Vars.endchange = "yes";
        }
        if (Vars.players == 2)
        {
            Vars.commtrigger = macros1.either(2, 3, 4);
        }
        if (Vars.players == 3)
        {
            Vars.commtrigger = macros1.either(3, 4, 5);
        }
        if (Vars.players == 4)
        {
            Vars.commtrigger = macros1.either(4, 5, 6);
        }
        if (Vars.players == 5)
        {
            Vars.commtrigger = macros1.either(5, 6, 7);
        }
        Vars.plareigng = 0;
        Vars.plbreigng = 0;
        Vars.plcreigng = 0;
        Vars.pldreigng = 0;
        Vars.plereigng = 0;
        Vars.plareigne = 0;
        Vars.plbreigne = 0;
        Vars.plcreigne = 0;
        Vars.pldreigne = 0;
        Vars.plereigne = 0;
        Vars.advisorcount = 0;
        Vars.crowncount = 0;
        Vars.reignsep = 0;
        Vars.weaponrew = 0;
