    {
        this.Passages[@"PeaceIntro"] = new StoryPassage(@"PeaceIntro", new string[] { "INTRO", }, passage42_Main);
    }

    IStoryThread passage42_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III - Peace Through War");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak(); //hr tag
        yield return text(@"I arrived just in time for the festivities. The normally dour gothic architecture was festooned with brightly colored ribbons, balloons, and pots overflowing with borscht. The conquering soldiers paraded down the cobblestone streets in formation and uniform, ticker tape celebrating the Separatists’ victory. Such a remarkable contrast between the slipshod militias of my youth and the democratic revolutionaries cheering the Hungarian name in time with each stomp of a soldier's boot.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"However, it was not this boring pageantry that ignited an infernal passion within me, it was the passion of the people. Emboldened by their conquest of a royal power and enlivened with pride in their country, this righteous fervor became a frenzy. Within weeks, an extreme nationalist party began to take hold and this brief respite from war was suddenly punctuated by lofty ambitions. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The government had realized that the only way to ensure a lasting peace in the country and the tumultuous surrounding territories was to properly exercise military force to coerce cooperation. My family's reputation within the scientific community had positioned me as the foremost authority in experimental weaponry. I relished the opportunity to observe the devastative effects of these marvelous machinations by attempting to take over the world.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"With my technological arsenal leading the charge, no nation could hope to resist our power! Our army would ensure a lasting peace that would enshrine my legacy forever in the annals of human history. There was not a moment to waste! It was time to change the world with science!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "SeparatistBarnCheck", null);
        yield return lineBreak();
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        Vars.wlimit = macros1.either(4, 5);
        if (Vars.warloser == "Separatists")
        {
            Vars.endchange = "yes";
        }
        Vars.pea1 = 0;
        Vars.pea2 = 0;
        Vars.pea3 = 0;
        yield break;
    }


