        yield return text(macros1.either(@"I alone deserved recognition for my glorious, bombastic, chimerical, transformative creations that defied the rigors of known science. I could no longer suffer the egotistical competitive nature of my cousins, whose work so paled in comparison to my own. This was my time. This was the era of " + name + " III!", @"The fate of the world rested in my hands. It was my discoveries, my ingenious weaponry, my unslakable ambitions that would define this new epoch in human existence. And I put on a demonstration that left no doubt as to whom the glory should be bestowed upon.", @"Fame meant little to me if it did not carry with it the power to alter the world. I would watch as it transformed - carefully molded by my own hands - into a boundless utopia. My influence could no longer be relegated to the shadows. It was time to claim the Earth for my own and shake it to its very core."));
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("To Battle");
        }
        yield return lineBreak();
        yield return text("All players take all their ");
        yield return text("<sprite=\"S3_WeaponToken\" index=0>");
        yield return text(" ");
        yield return text(@"tokens into their hands. For each battle, starting with the upper-most territory (marked by the Occult cube), the players secretly decide how many tokens to place into their right hand and extend their fist to the center of the table. Once all players have decided, all players reveal their tokens.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The player(s) who revealed the most tokens receives the VP listed. If more than o" +
            "ne player revealed the same amount, all players that revealed the most tokens re" +
            "ceive all points. ");
        using (styleScope("bold", true))
        {
            using (styleScope("italic", true))
            {
                yield return text("ALL revealed tokens are placed into the supply, no matter the outcome.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("This process is then repeated by moving the Occult cube to the next square, until" +
            " all battles have been resolved.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("You must reveal at least 1 token to receive points. If no player reveals a token," +
            " then no players score VP and the next battle begins.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to begin the battle...", "BattleCompleteReturn", null);
        yield return lineBreak();
        yield break;
    }


