        {
            yield return text("Because of our decision, the ");
            using (styleScope("bold", true))
            {
                yield return text("Barracks are not built in town");
            }
            yield return text(". Whatever escalating tension had occurred in the original timeline was mended, o" +
            "r at least it was dulled.");
        }
        else //if (Vars.barracks == "no")
        {
            yield return text("Because of our decision, the ");
            using (styleScope("bold", true))
            {
                yield return text("Barracks are built in town");
            }
            yield return text(". Whatever escalating tension had occurred in the original timeline was mended, o" +
            "r at least it was dulled.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "SeedResolution", null);
        yield return text(" ");
        yield return lineBreak();
        yield break;
    }


