    IStoryThread passage134_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Afternoon Tea");
        }
        yield return lineBreak();
        if (Vars.bldg1 == 0 || Vars.bldg1 == "")
        {
            Vars.teaopt = "Barracks";
        }
        else
