        using (styleScope("bold", true))
        {
            yield return text("All players may again view the Storybook.");
        }
        yield return lineBreak();
        yield return lineBreak(); //hr tag
        yield return lineBreak();
        yield return text(@"It was absolutely dreadful. Astringent tea from an obscure area of the orient - bitter, stale cranberry scones, wildflower honey, and store-bought cream - this was without question the worst tea party to which I had ever had the displeasure of an invitation. And to think, the Monarchy was responsible for such a wasted afternoon.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("What kind of aristocracy was this? It made me re-evaluate my position entirely. I" +
            "f I could be served indigestible digestives then perhaps I should cause the nobi" +
            "lity a little indigestion in response by burning down the ");
        yield return text(Vars.teaopt);
        yield return text("! It would certainly remove the requirement to visit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("However, a plan as critical as this one required a conspiracy to execute. Therefo" +
            "re, regretably, the fate of the operation was left to the whims of my family, wh" +
            "om I loved dearly.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Click to continue...", "2PAfternoonBid", null);
        }
        else
        {
            yield return link("Click to continue...", "AfternoonTeab", null);
        }
        yield return lineBreak();
        yield break;
    }


