    // #139: CoWEvent

    void passage139_Init()
    {
        this.Passages[@"CoWEvent"] = new StoryPassage(@"CoWEvent", new string[] { }, passage139_Main);
    }

    IStoryThread passage139_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Where Duty Lies");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ah, to be born of noble blood is a very troublesome thing. The townsfolk genuflect in my presence, the local military is willing to accept my generous donations, and the crown feels nearer to me than ever, yet still I am wrenched apart from within. Did my loyalties lay with the state or with myself?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The decision could not rest with me alone, unfortunately. But if my cousins - who" +
            "m I love so dearly - and I, could combine our interests, the aristocracy would s" +
            "urely take note. Would the region be ruled by a monarchy with a strong, ");
        using (styleScope("bold", true))
        {
            yield return text("iron fist");
        }
        yield return text(", crushing opposition and caring little for the welfare of its citizenry? Or woul" +
            "d the ");
        using (styleScope("bold", true))
        {
            yield return text("benevolent");
        }
        yield return text(" ");
        yield return text("rallying of the people serve us best in the end, despite the additional royal scrutiny it would incur?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Perhaps our early actions had already helped confirm our convictions, either way," +
            " the time had come to make a decision. For ");
        yield return text(Vars.townname);
        yield return text(", we knew what was best.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Click here to continue...", "2PCoWEvent", null);
        }
        else
        {
            yield return link("Click here to continue...", "CoWEventb", null);
        }
        yield return lineBreak();
        yield break;
    }


