        using (styleScope("bold", true))
        {
            yield return text("War on the Horizon");
        }
        yield return lineBreak();
        yield return text(@"The spectre of war haunted the small village. This ideological tension would erupt in loud displays and gatherings of the peasantry near the Town Hall. For all the folderol, I began to cherish the moments when the eerie stillness of the evening was broken by anguished yells.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The Separatists felt alienated by the aristocratic government and wished to secede. Their brash tactics aimed to incite a democratic revolt among the proletariat. The Unified Monarchists feared the anarchic destabilization of the economy at such a key moment during industrialization. I was quickly able to determine that ");
        using (styleScope("bold", true))
        {
            yield return text("the town supported the ");
            yield return text(Vars.warwinner);
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Click to continue...", passage149_Fragment_1);
        using (styleScope("hook", "h0000149"))
            yield return link("Click to continue...", null, () => enchantHook("h0000149", HarloweEnchantCommand.Replace, passage149_Fragment_0));
        yield return lineBreak();
        yield break;
