    // .............
    // #150: ParadoxTimeRandom

    void passage150_Init()
    {
        this.Passages[@"ParadoxTimeRandom"] = new StoryPassage(@"ParadoxTimeRandom", new string[] { "Incomplete", }, passage150_Main);
    }

    IStoryThread passage150_Main()
    {
        if (Vars.timemistake == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Surge of Productivity");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"The time device proved to be invaluable for productivity. While the general populace squabbled over self-interests, creating and destroying the countryside in equal measure with varying degrees of incalculable existential horror, I was generally left to my leisure in solitude with my spouse and servants.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"One flick of an electrical switch and the copper fixtures of the device sent me back to the moments before a failed experiment. I soon became acquainted with visitations from myself, even sharing tea with several versions of my person to talk over and revise a particularly difficult thesis. While the process aged me quicker than desired, the ingredients it saved and the excellent conversation proved well worth it.");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 2)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Clarity of Purpose");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Technological advancement retrieved from the future, the stability offered by knowing you can change your past, the ability to travel backwards in time to guide one's self away from a rough day ahead; general access to a time machine could lift a near Utopia right to the edge of perfection!");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"While I was somewhat disappointed in the lack of chaos, I was ecstatic at the reaction of the university elite. Our decision had such a positive effect on the world, it made the academics positively seethe! Those furrowed brows and anxious worry lines grafted onto their imbecilic faces made the outcome of this rash decision a joy to behold. It wasn't long before this joy gave way to clarity of purpose. I felt reinvigorated, hoping each day that my next experiment would evoke the same horrific response.");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 3)
        {
            using (styleScope("bold", true))
            {
                yield return text("None Left Behind");
            }
            yield return lineBreak();
            yield return text(@"If I were to forgo humility for a moment and describe one of my most favorable traits, I am a creature of infinite patience. So, I watched as the first experiments in time alteration bore miniscule results and continued in my tasks without paying them much heed. Like all initial fascinations, the wave of interest in manipulating fate slowly gave way to other technological distractions and time machines became popular children's toys around the holidays.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"I cannot recollect the moment when I noticed it, perhaps it happened naturally, but as the timeline shifted ever so slowly, it appeared that the forces aligning the cosmos preferred stasis over the whims of chaos. With each passing season, the studious gap between myself and my cousins seemed to edge ever closer.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("And though I abhorred the thought of intervention from forces outside of my under" +
            "standing, I cannot say that I did not relish my stoicism being rewarded.");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 4)
        {
            using (styleScope("bold", true))
            {
                yield return text("Future Notes");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("There are narrative consequences for unleashing a Time Machine into the wild, and" +
            " the devastation is too far-reaching for one single paragraph in a mad scientist" +
            "\'s memoir to detail. However, it has ");
            using (styleScope("bold", true))
            {
                yield return text("no effect on gameplay");
            }
            yield return text(" and therefore will be omitted. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"It is better to write these words now in anticipation of the game, My Father's Work, which will see release in 2022 and detail the historical events of my family. I've played it a few times during my travels and while I wish it had a solo version, it's still very good. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Perhaps history will no longer align with the narrative presented in the game and" +
            " this paragraph will seem oddly out of place. Ah, such is the confounding nature" +
            " of time travel.");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 5)
        {
            using (styleScope("bold", true))
            {
                yield return text("Trust and Benevolence");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"The people have developed a sense of trust and acceptance for my work after the unmitigated success of the time altering apparatus. Trust and acceptance? I grapple with this concept with many of my waking hours. Even on the days where I feel emboldened to venture backwards into the timestream to undo this stomach-turning adoration, some peon in the village simply undoes my work.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"My beautifully macabre estate is now looked upon with exuberance by tourists to the region. Tourists! By god, this will make pushing the boundaries of ethical imagination nearly impossible! I must break through this irrational barrier of love and generosity before it stifles my work!");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 6)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Return to Suspicion");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("How could they accuse us of sedition? The Time Machine was my family\'s gift to al" +
            "l of humanity and yet they call it willfully negligent and unethical!");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Do we blame Prometheus for every home burnt to the ground because of the invention of fire? Is the zoetrope responsible for every detestable piece of film created after it? Should we ban perfumes and colognes for their ability to more fervently entice couples into intimacy? It is only natural that the most important discoveries carry with them a modicum of insidious potential.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("It is absurd that a correlative effect is so readily pinned upon me. Yet, their s" +
            "uperstitions have once again returned! ");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 7)
        {
            using (styleScope("bold", true))
            {
                yield return text("Targeted");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("They discovered who did it. Hungarian government tracked it. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Perhaps it was easy to discern this information as every pamphlet, editorial, journal, and detailed blueprint was signed in bold ink. It was all for naught as well. The Hungarian government quietly tracked each copy down with the assistance of the scientific community, and secured this knowledge for themselves alone.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"My family's decision to disseminate this information had dire consequences for those that chose this path. Their Masterwork was rendered pointless to complete as it would be confiscated immediately by police force emboldened by access to the time stream. Fortunately, those that decided to remain silent could not be implicated merely by association and remained free to continue their work.");
            yield return lineBreak();
            yield return lineBreak();

        }
        if (Vars.timemistake == 8)
        {
            using (styleScope("bold", true))
            {
                yield return text("Utter Catastrophe");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"There is always a cycle of destruction and renewal with every major epoch in the world's history, and this would probably be seen as a minor stumbling block in the overall chronology of events. With the ease of general access to a device that had the power to bend time and space around it, it was soon discovered that the average individual may have lacked the self-control and intelligence required to prevent the catastrophic destruction of nearly every living thing in Eastern Europe. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Owning an Estate made of stone, looming high above the valley, I was able to reta" +
            "in most of my possessions. Although the air was now tinged with a hint of sulfur" +
            " and resources were a touch harder to procure.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("This was a minor setback.");
            yield return lineBreak();
            yield return lineBreak();

        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h0000150"))
            yield return link("Click to continue...", null, () => enchantHook("h0000150", HarloweEnchantCommand.Replace, passage150_Fragment_0));
        //if (Vars.timemistake == 6)
        //{
        //    yield return link("Click to continue...", "Paradox3b", null);
        //}
        //else if (Vars.timemistake == 8)
        //{
        //    yield return link("Click to continue...", "Paradox3b", null);
        //}
        //else
        //{
        //    yield return link("Click to continue...", "Paradox3", null);
        //}
        yield break;
    }

