    }

    IStoryThread passage172_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Famine");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Because of the rapid expansion of war efforts, stocks of goods were increasingly hard to come by. When a famine struck in 1901, the food shortages caused mass riots. Ideas were thrown about for potential solutions - labor camps for dissidents, re-education facilities, pills that slow the metabolism - but all of these were bandages that did not address the root of the issue.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"While I offered it in jest at first, the most clean, efficient, and logical course was to utilize what we now had in droves to offset what we lacked. Were we to simply riddle our enemy's bodies with bullets and let them spoil the soil? Why should we allow perfectly good protein to waste away in the elements?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I decided to convene with my cousins and put the matter to a vote.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("We could continue to provide empty promises of more food in the future and preach" +
            " hardiness and austerity. Or we could provide a ");
        using (styleScope("bold", true))
        {
            yield return text("real");
        }
        yield return text(", sustainable solution that would guarantee success on the battlefield.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Click to continue...", "2PFamineBid", null);
        }
        else
        {
            yield return link("Click to continue...", "ATOW-FamineEventV", null);
        }
        yield return lineBreak();
        yield break;
    }


