            yield return text("Time Machine - Publication?");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"While the ideas set forth in my parent's journal entries were both outdated and embarrassingly rudimentary in some areas, one thing that the fools in academia hounded us to provide was the schematics to the Time Conveyance Device. For a discovery so radical and immense in its influence on multiple dimensions of the world, the meager sums they offered for entrusting it to their universities was insulting.");
