        using (styleScope("bold", true))
        {
            yield return text("The War?");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("As a brief consideration for those who may read these words and perceive a gap in" +
            " the narrative of my family\'s lineage, I will address the period of civil war th" +
            "at was mentioned so often a full generation previous. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Though details about this minor conflict are sparse, I could discern that ");
        //yield return lineBreak();
