            yield return text("the ");
            yield return text(Vars.warwinner);
            yield return text(" were able to use public pressure to establish a republican house with only minor s" +
            "kirmishes and rebellions along the way. Working in tandem with a figurehead mona" +
            "rchy, a democratic process was enacted.");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("Decidedly trivial and woefully boring, I could not understand my family\'s fascina" +
            "tion with the events. Suffice to say, it had minimal effects on my current state" +
            ".");
        }
        else //if (Vars.warwinner == "Unified Monarchists")
        {
            yield return text("the ");
            yield return text(Vars.warwinner);
            yield return text(" were able to quash the minor events of the 1860\'s and 70\'s, easing minor taxation " +
            "grievances and relegating this civil war to a few muckraking, sensationalist hea" +
            "dlines in the emerging newspapers.");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("In fact, it was so difficult to find materials related to the disagreement that I" +
            " could not understand my family\'s fascination with the events. Suffice to say, i" +
            "t had minimal effects on my current affairs.");
