            yield return text("A Time for Sabotage");
        }
        yield return lineBreak();
        yield return text(@"For too long I had been ignored! One might ask what accursed schemes would push one towards the illicit undertaking of sabotage? I ask, is it not enough to feel forgotten, downtrodden, unloved, and spited by those who would in the same breath speak of you as a colleague?");
