    IStoryThread passage229_Main()
    {
        if (Vars.release >= 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Bend Towards Chaos");
            }
            yield return lineBreak(); //br tag
            yield return text(@"To hell with academia! I was not afraid of some minor fourth-dimensial tampering. Would it not be immoral to refuse all persons the basic human right to alter their own fate? I would unlock and disperse the secrets of creation no matter what horrors lay before me.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Publishing the means to construct a time machine to the general public was a calculated move that even the most daring polymath wouldn't be brave enough to make. My family would leave an indelible mark on the timeline of the cosmos regardless of the anarchic course that now lay ahead.");
        }
        else
        {
            using (styleScope("bold", true))
            {
                yield return text("A Secure Future");
            }
            yield return lineBreak(); //br tag
            yield return text(@"Bold as it would have been to openly allow the public to source parts and make their own journey through time, the potential time loss was too great to ignore. With the future already at my fingertips, there was no need to ride the waves of chaos. With the precision of a potter molding clay at the wheel, I would design a perfect world.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Because of our decision, the town has seen the brilliance of our vision and will " +
            "honor the best amongst us appropriately with a special monument.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Click to continue...", passage229_Fragment_1);
        using (styleScope("hook", "h0000"))
            yield return link("Click to continue...", null, () => enchantHook("h0000", HarloweEnchantCommand.Replace, passage229_Fragment_0));
        yield return lineBreak();
        yield break;
