    // .............
    // #242: PeacetoRebuild

    void passage242_Init()
    {
        this.Passages[@"PeacetoRebuild"] = new StoryPassage(@"PeacetoRebuild", new string[] { }, passage242_Main);
    }

    IStoryThread passage242_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("The Price of Peace");
        }
        yield return lineBreak();
        yield return text(@"The wounds of the recent civil war were still raw and the process of rebuilding was not an inexpensive proposition. While I pledged to offer assistance in any way that my humble, self-driven, well-educated mind could, I was quite surprised when they actually had the indecency to act upon this proposal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The Separatist government enforced ");
        if (Vars.wardestroy == 0)
        {
            yield return text("no new taxes, thankfully, as zero buildings were sabotaged in the previous genera" +
            "tion. At least consistent support for my native country had its benefits.");
        }
        else if (Vars.wardestroy == 1)
        {
            yield return text("a one-time estate inheritance tax of $1 - due to a single building being destroye" +
            "d - which would go into effect during my early years. While at least it would no" +
            "t rob me of my most precious resource - time - it would sour my mood upon days o" +
            "f leisure.");
        }
        else //Vars.wardestroy == 2)
        {
            yield return text("a recurring estate tax of $1 - to rebuild several buildings - that would go into " +
            "effect consistently ");
            using (styleScope("italic", true))
            {
                yield return text("(at the start of each new round)");
            }
            yield return text(". While at least it would not rob me of my most precious resource - time - it wou" +
            "ld sour my mood upon days of leisure.");
        }
        yield return text(" ");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "PeaceDiscard", null);
        yield return lineBreak();
        yield break;
    }


