    // #262: 2PBlameGameEvent

    void passage262_Init()
    {
        this.Passages[@"2PBlameGameEvent"] = new StoryPassage(@"2PBlameGameEvent", new string[] { }, passage262_Main);
    }

    IStoryThread passage262_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("The Dilemma");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"My cousin and I were about to be faced with a pivotal decision when a group of loyal soldiers arrived at our doorstep. In the previous months we had made a simple pact to keep the knowledge of our activities secret. But alliances are particularly tenuous when multiple timelines overlap. ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Could I trust my own flesh and blood to honor our agreement?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Rules");
        }
        yield return lineBreak();
        yield return text("If both players ");
        using (styleScope("italic", true))
        {
            yield return text("remain silent");
        }
        yield return text(", they will each ");
        using (styleScope("bold", true))
        {
            yield return text("gain 2 Resources ");
            using (styleScope("italic", true))
            {
                yield return text("(Knowledge or Ingredients)");
            }
            yield return text(" ");
            yield return text("of their choice at the start of the next Generation.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("If both players ");
        using (styleScope("italic", true))
        {
            yield return text("accuse");
        }
        yield return text(" ");
        yield return text("one another of traitorous activity, they both must ");
        using (styleScope("bold", true))
        {
            yield return text("discard 2 Resources");
        }
        yield return text(" ");
        yield return text("of any type from their Estate or ");
        using (styleScope("bold", true))
        {
            yield return text("return a Servant to Lost");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("If one player accuses and the other remains silent, the player who remains silent" +
            " must ");
        using (styleScope("bold", true))
        {
            yield return text("immediately discard one Estate Upgrade from their Estate and gains 2 ");
            yield return text("<sprite=\"Creepy_Icon\" index=0>");
            yield return text(".");
        }
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("If they do not have an Estate Upgrade built, they must instead lose 5VP.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "Blame1", null);
        yield return text(" ");
        yield return lineBreak();
        yield break;
    }


