        yield return lineBreak();
        yield return text(@"Being well-versed in simple arcane practices - a fact I did not relay to my well-fed companion - I offered my assistance in the matter. General summoning of the spirits of the dead would provide cover for some of my family's peculiar traits, but perhaps I could provide a heretic for the royals to dislike.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("The choice was obvious to me:");
