        using (styleScope("bold", true))
        {
            yield return text("The Choice of Recognition");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"As fortune would have it, my esteemed companion, the royal advisor had quickly imbibed the majority of bottle of absinthe and promptly passed out upon the floor amongst his own evening's meal. Still lain fresh upon the dinner table was a contract with a royal seal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Now, I would not stoop to signing banker's cheques that were not my own, but considering the paper did require advisement as to whom should receive said goods or title, I was intrigued by the possibility and took up the authority. I could sign my name to the document, thereby granting myself any title or I could procure a little extra business in the region. It would be somewhat selfish to simply take the title, but it was alluring nonetheless.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("The choice was clear to me. I chose:");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h000030500"))
            yield return link("A little for myself.", null, () => enchantHook("h000030500", HarloweEnchantCommand.Replace, passage305_Fragment_0));
        yield return text(" <i>This will result in: " + Vars.crownL + " " + Vars.ch1 + "</i>");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h000030501"))
            yield return link("Glory to ME.", null, () => enchantHook("h000030501", HarloweEnchantCommand.Replace, passage305_Fragment_1));
        yield return text("<i>This will result in: " + Vars.crownR + " Choose your own title that will displ" +
            "ay with your name for the rest of the story.</i>");
        yield return lineBreak();
        yield break;
    }

