    // .............
    // #293: SeedResolution

    void passage315_Init()
    {
        this.Passages[@"SeedResolution"] = new StoryPassage(@"SeedResolution", new string[] { "revised", }, passage315_Main);
    }

    IStoryThread passage315_Main()
    {
        if (Vars.gunsbonus == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Place of Knowledge");
            }
            yield return lineBreak();
            yield return text("I watched from my clandestine position as a singular corner in the secret laboratory became a storage place for various notes and torn pages from old manuscripts. With each passing evening, this obsessive collection of knowledge spilled onto the stone floors and tacked up on the walls like an artist's studio, spreading across the room like brown leaves on a brilliant vine. Such a wealth of knowledge, the likes of which I had never witnessed in all of my years at university.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Soon, it was impossible for ");
            yield return text(Vars.townname);
            yield return text(" to ignore the genius that existed just outside its very limits. The region would be celebrated for the <b>knowledge</b> my family had brought to it, and I savored the victory from the shadows, knowing I would reap all the benefits.");
            yield return lineBreak();
        }
        else if (Vars.gunsbonus == 2)
        {
            using (styleScope("bold", true))
            {
                yield return text("A Wealth of Goods");
            }
            yield return lineBreak();
            yield return text("Ingredients lay stacked in haphazard piles along the stone floor of the laboratory. The estate grounds were well-grazed by the exotic display of zoological treats my parents collected. It was difficult to maintain my secretive ruse as an oblivious family member with such a wealth of potential hiding just below my feet. It was a magnificent sight.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Soon, it was impossible for ");
            yield return text(Vars.townname);
            yield return text(" to ignore the genius that existed just outside its very limits. The region would be celebrated for the <b>goods</b> my family had brought to it, and I savored the victory from the shadows, knowing I would reap all the benefits.");
            yield return lineBreak();
        }
        else
        {
            using (styleScope("bold", true))
            {
                yield return text("An Investor's Paradise");
            }
            yield return lineBreak();
            yield return text("Even in their sunset years, my parents operated their business interests with a voracity - and veracity - that could only be seen to be believed. If I can be perfectly quaint, the glitter of coin held little interest to me, yet the wondrous things which I could procure with it certainly reignited the fires of ambition within me as my hair grew ever ashen.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Soon, it was impossible for ");
            yield return text(Vars.townname);
            yield return text(" to ignore the genius that existed just outside its very limits. The region would be celebrated for the <b>money</b> my family had brought to it, and I savored the victory from the shadows, knowing I would reap all the benefits.");
            yield return lineBreak();
        }
        yield return lineBreak();
        using (styleScope("hook", "h00000315"))
            yield return link("Click to continue...", null, () => enchantHook("h00000315", HarloweEnchantCommand.Replace, passage315_Fragment_0));
        yield return lineBreak();
        yield break;
    }

